public class ParseBenchmarkTest {

  private ParseBenchmark parseBenchmark;

  @BeforeEach
  void init() {
    parseBenchmark = new ParseBenchmark();
  }

  @Test
  void testSetUp() throws Exception {
    // Prepare mocks and set fields
    // Mock Document enum with name() returning "testdoc"
    ParseBenchmark.Document mockDocument = mock(ParseBenchmark.Document.class);
    when(mockDocument.name()).thenReturn("testdoc");

    // Mock Api with newParser() returning a mock Parser
    ParseBenchmark.Api mockApi = mock(ParseBenchmark.Api.class);
    ParseBenchmark.Parser mockParser = mock(ParseBenchmark.Parser.class);
    when(mockApi.newParser()).thenReturn(mockParser);

    // Set private fields document and api
    setField(parseBenchmark, "document", mockDocument);
    setField(parseBenchmark, "api", mockApi);

    // Mock static method resourceToString to return known string
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class)) {
      mockedStatic.when(() -> ParseBenchmark.resourceToString("testdoc.json")).thenReturn("jsoncontent");

      // Invoke private method setUp() via reflection
      Method setUpMethod = ParseBenchmark.class.getDeclaredMethod("setUp");
      setUpMethod.setAccessible(true);
      setUpMethod.invoke(parseBenchmark);

      // Verify that resourceToString was called correctly
      mockedStatic.verify(() -> ParseBenchmark.resourceToString("testdoc.json"));

      // Verify fields text and parser are set correctly
      char[] text = (char[]) getField(parseBenchmark, "text");
      assertArrayEquals("jsoncontent".toCharArray(), text);

      Object parser = getField(parseBenchmark, "parser");
      assertSame(mockParser, parser);
    }
  }

  // Helper method to set private field via reflection
  private static void setField(Object target, String fieldName, Object value) throws Exception {
    Field field = target.getClass().getDeclaredField(fieldName);
    field.setAccessible(true);
    field.set(target, value);
  }

  // Helper method to get private field via reflection
  private static Object getField(Object target, String fieldName) throws Exception {
    Field field = target.getClass().getDeclaredField(fieldName);
    field.setAccessible(true);
    return field.get(target);
  }
}

